83	Array<int64_t> BatchDecodeWithPagedKVCacheWorkspaceSize(
84	    TensorView device_buffer, TensorView indptr, int64_t batch_size, int64_t num_qo_heads,
85	    int64_t num_kv_heads, int64_t page_size, bool enable_cuda_graph, int64_t window_left,
86	    double logits_soft_cap, int64_t head_dim_qk, int64_t head_dim_vo, TensorView empty_q_data,
87	    TensorView empty_kv_data) {
88	  (void)window_left;
89	  (void)logits_soft_cap;
90	  (void)empty_q_data;
91	  (void)empty_kv_data;
92	  CHECK_INPUT_TYPE(indptr, dl_int32);
93	
94	  TVM_FFI_ICHECK_EQ(head_dim_qk, head_dim_vo)
95	      << "CUDA cores template only supports equal head dim for QK and VO, please use tensor "
96	         "cores template for different head dim";
97	
98	  ffi::CUDADeviceGuard device_guard(device_buffer.device().device_id);
99	  const cudaStream_t stream = get_stream(device_buffer.device());
100	  size_t float_workspace_size_in_bytes = 0;
101	  size_t int_workspace_size_in_bytes = 0;
102	
103	  DISPATCH_context(
104	      DTypeQ, DTypeKV, DTypeO, IdType, HEAD_DIM_QK, HEAD_DIM_VO, POS_ENCODING_MODE,
105	      USE_SLIDING_WINDOW, USE_LOGITS_SOFT_CAP, AttentionVariant, Params, [&] {
106	        DISPATCH_GQA_GROUP_SIZE(num_qo_heads / num_kv_heads, GROUP_SIZE, {
107	          auto work_estimation_func = BatchDecodeWithPagedKVCacheWorkEstimationDispatched<
108	              GROUP_SIZE, HEAD_DIM_QK, POS_ENCODING_MODE, AttentionVariant, Params>;
109	          cudaError_t status =
110	              DecodePlanWorkspaceSize<HEAD_DIM_QK, POS_ENCODING_MODE, AttentionVariant, Params>(
111	                  float_workspace_size_in_bytes, int_workspace_size_in_bytes,
112	                  static_cast<IdType*>(indptr.data_ptr()), batch_size, num_qo_heads, page_size,
113	                  enable_cuda_graph, /*stream=*/stream, work_estimation_func);
114	
115	          TVM_FFI_ICHECK(status == cudaSuccess)
116	              << "BatchDecodeWithPagedKVCache workspace size failed with error "
117	              << cudaGetErrorString(status);
118	          return true;
119	        });
120	      });
121	
122	  std::vector<int64_t> workspace_sizes = {
123	      static_cast<int64_t>(float_workspace_size_in_bytes),
124	      static_cast<int64_t>(int_workspace_size_in_bytes),
125	  };
126	  return Array(workspace_sizes);
