129	void BatchDecodeWithPagedKVCacheRun(TensorView float_workspace_buffer,
130	                                    TensorView int_workspace_buffer, Array<int64_t> plan_info_vec,
131	                                    TensorView q, TensorView paged_k_cache,
132	                                    TensorView paged_v_cache, TensorView paged_kv_indptr,
133	                                    TensorView paged_kv_indices, TensorView paged_kv_last_page_len,
134	                                    TensorView o, Optional<TensorView> maybe_lse,
135	                                    int64_t kv_layout_code, int64_t window_left,
136	                                    bool enable_pdl ADDITIONAL_FUNC_PARAMS) {
137	  CHECK_INPUT_TYPE(paged_kv_indptr, dl_int32);
138	  CHECK_INPUT_TYPE(paged_kv_indices, dl_int32);
139	  CHECK_INPUT_TYPE(paged_kv_last_page_len, dl_int32);
140	
141	  DecodePlanInfo plan_info;
142	  plan_info.FromVector(std::vector<int64_t>(plan_info_vec.begin(), plan_info_vec.end()));
143	  QKVLayout kv_layout = static_cast<QKVLayout>(kv_layout_code);
144	  int64_t batch_size = q.size(0);
145	  int64_t num_qo_heads = q.size(1);
146	  int64_t num_kv_heads, page_size;
147	
148	  if (kv_layout == QKVLayout::kHND) {
149	    num_kv_heads = paged_k_cache.size(1);
150	    page_size = paged_k_cache.size(2);
151	  } else {
152	    page_size = paged_k_cache.size(1);
153	    num_kv_heads = paged_k_cache.size(2);
154	  }
155	  uint32_t head_dim_qk = q.size(2);
156	  uint32_t head_dim_vo = paged_v_cache.size(3);
157	
158	  TVM_FFI_ICHECK_EQ(head_dim_qk, head_dim_vo)
159	      << "CUDA cores template only supports equal head dim for QK and VO, please use tensor "
160	         "cores template for different head dim";
161	
162	  if (maybe_lse.has_value()) {
163	    const auto& lse = maybe_lse.value();
164	    TVM_FFI_ICHECK_EQ(lse.size(0), batch_size);
165	    TVM_FFI_ICHECK_EQ(lse.size(1), num_qo_heads);
166	  }
167	
168	  void* float_buffer = static_cast<void*>(float_workspace_buffer.data_ptr());
169	  void* int_buffer = static_cast<void*>(int_workspace_buffer.data_ptr());
170	
171	  // get q_stride_n and q_stride_h
172	  const auto q_stride_n = q.stride(0);
173	  const auto q_stride_h = q.stride(1);
174	
175	  // get kv_cache_strides
176	  const int64_t* kv_cache_strides = nullptr;
177	  auto k_strides = paged_k_cache.strides();
178	  auto v_strides = paged_v_cache.strides();
179	  TVM_FFI_ICHECK_EQ(k_strides.size(), v_strides.size());
180	  for (int i = 0; i < k_strides.size(); ++i) {
181	    TVM_FFI_ICHECK_EQ(k_strides[i], v_strides[i]);
182	  }
183	  kv_cache_strides = k_strides.data();
184	
185	  ffi::CUDADeviceGuard device_guard(q.device().device_id);
186	  const cudaStream_t stream = get_stream(q.device());
187	
188	  DISPATCH_context(
189	      DTypeQ, DTypeKV, DTypeO, IdType, HEAD_DIM_QK, HEAD_DIM_VO, POS_ENCODING_MODE,
190	      USE_SLIDING_WINDOW, USE_LOGITS_SOFT_CAP, AttentionVariant, Params, [&] {
191	        paged_kv_t<DTypeKV, IdType> paged_kv(
192	            num_kv_heads, page_size, HEAD_DIM_QK, batch_size, kv_layout,
193	            static_cast<DTypeKV*>(paged_k_cache.data_ptr()),
194	            static_cast<DTypeKV*>(paged_v_cache.data_ptr()), kv_cache_strides,
195	            static_cast<IdType*>(paged_kv_indices.data_ptr()),
196	            static_cast<IdType*>(paged_kv_indptr.data_ptr()),
197	            static_cast<IdType*>(paged_kv_last_page_len.data_ptr()));
198	
199	        Params params;
200	        params.q = static_cast<DTypeQ*>(q.data_ptr());
201	        params.paged_kv = paged_kv;
202	        params.o = static_cast<DTypeO*>(o.data_ptr());
203	        params.lse =
204	            maybe_lse.has_value() ? static_cast<float*>(maybe_lse.value().data_ptr()) : nullptr;
205	        params.padded_batch_size = 0;
206	        params.num_qo_heads = num_qo_heads;
207	        params.q_stride_n = q_stride_n;
208	        params.q_stride_h = q_stride_h;
209	        params.window_left = window_left;
210	        params.request_indices = nullptr;
211	        params.kv_tile_indices = nullptr;
212	        params.o_indptr = nullptr;
213	        params.kv_chunk_size_ptr = nullptr;
214	        params.block_valid_mask = nullptr;
215	        params.partition_kv = false;
216	
217	        ADDITIONAL_PARAMS_SETTER
218	
219	        DTypeO* tmp_v = nullptr;
220	        float* tmp_s = nullptr;
221	        params.request_indices =
222	            GetPtrFromBaseOffset<IdType>(int_buffer, plan_info.request_indices_offset);
223	        params.kv_tile_indices =
224	            GetPtrFromBaseOffset<IdType>(int_buffer, plan_info.kv_tile_indices_offset);
225	        params.o_indptr = GetPtrFromBaseOffset<IdType>(int_buffer, plan_info.o_indptr_offset);
226	        params.kv_chunk_size_ptr =
227	            GetPtrFromBaseOffset<IdType>(int_buffer, plan_info.kv_chunk_size_ptr_offset);
228	        if (plan_info.split_kv) {
229	          tmp_v = GetPtrFromBaseOffset<DTypeO>(float_buffer, plan_info.v_offset);
230	          tmp_s = GetPtrFromBaseOffset<float>(float_buffer, plan_info.s_offset);
231	          if (plan_info.enable_cuda_graph) {
232	            params.block_valid_mask =
233	                GetPtrFromBaseOffset<bool>(int_buffer, plan_info.block_valid_mask_offset);
234	          }
235	        }
236	        params.padded_batch_size = plan_info.padded_batch_size;
237	
238	        cudaError_t status =
239	            flashinfer::BatchDecodeWithPagedKVCacheDispatched<HEAD_DIM_QK, POS_ENCODING_MODE,
240	                                                              AttentionVariant>(params, tmp_v,
241	                                                                                tmp_s, enable_pdl,
242	                                                                                /*stream=*/stream);
243	        TVM_FFI_ICHECK(status == cudaSuccess)
244	            << "BatchDecodeWithPagedKVCache failed with error " << cudaGetErrorString(status);
245	        return true;
246	      });
247	}
